PRAGMA foreign_keys=OFF;
BEGIN TRANSACTION;
CREATE TABLE IF NOT EXISTS "migrations" ("id" integer primary key autoincrement not null, "migration" varchar not null, "batch" integer not null);
CREATE TABLE IF NOT EXISTS "password_reset_tokens" ("email" varchar not null, "token" varchar not null, "created_at" datetime, primary key ("email"));
CREATE TABLE IF NOT EXISTS "sessions" ("id" varchar not null, "user_id" integer, "ip_address" varchar, "user_agent" text, "payload" text not null, "last_activity" integer not null, primary key ("id"));
CREATE TABLE IF NOT EXISTS "cache" ("key" varchar not null, "value" text not null, "expiration" integer not null, primary key ("key"));
CREATE TABLE IF NOT EXISTS "cache_locks" ("key" varchar not null, "owner" varchar not null, "expiration" integer not null, primary key ("key"));
CREATE TABLE IF NOT EXISTS "jobs" ("id" integer primary key autoincrement not null, "queue" varchar not null, "payload" text not null, "attempts" integer not null, "reserved_at" integer, "available_at" integer not null, "created_at" integer not null);
CREATE TABLE IF NOT EXISTS "job_batches" ("id" varchar not null, "name" varchar not null, "total_jobs" integer not null, "pending_jobs" integer not null, "failed_jobs" integer not null, "failed_job_ids" text not null, "options" text, "cancelled_at" integer, "created_at" integer not null, "finished_at" integer, primary key ("id"));
CREATE TABLE IF NOT EXISTS "failed_jobs" ("id" integer primary key autoincrement not null, "uuid" varchar not null, "connection" text not null, "queue" text not null, "payload" text not null, "exception" text not null, "failed_at" datetime not null default CURRENT_TIMESTAMP);
CREATE TABLE IF NOT EXISTS "personal_access_tokens" ("id" integer primary key autoincrement not null, "tokenable_type" varchar not null, "tokenable_id" integer not null, "name" text not null, "token" varchar not null, "abilities" text, "last_used_at" datetime, "expires_at" datetime, "created_at" datetime, "updated_at" datetime);
CREATE TABLE IF NOT EXISTS "users" ("id" integer primary key autoincrement not null, "name" varchar not null, "email" varchar not null, "email_verified_at" datetime, "password" varchar, "remember_token" varchar, "created_at" datetime, "updated_at" datetime, "google_id" varchar, "apple_id" varchar, "avatar" varchar, "role" varchar not null default 'user', "phone" varchar, "balance" numeric not null default '0', "total_profit" numeric not null default '0', "total_invested" numeric not null default '0', "withdrawal_date" date, "bank_name" varchar, "bank_account_holder" varchar, "bank_account_number" varchar, "bank_routing_number" varchar, "account_type" varchar, "password_reset_otp" varchar, "otp_expires_at" datetime, "email_verification_code" varchar, "email_verification_expires_at" datetime, "lxp_id" varchar);
CREATE TABLE IF NOT EXISTS "investment_plans" ("id" integer primary key autoincrement not null, "name" varchar not null, "description" text, "min_amount" numeric not null, "max_amount" numeric not null, "interest_rate" numeric not null, "duration_days" integer not null, "return_type" varchar not null default 'daily', "is_active" tinyint(1) not null default '1', "created_at" datetime, "updated_at" datetime);
CREATE TABLE IF NOT EXISTS "transactions" ("id" integer primary key autoincrement not null, "user_id" integer not null, "type" varchar not null, "amount" numeric not null, "status" varchar not null default 'pending', "method" varchar, "reference" varchar, "description" text, "created_at" datetime, "updated_at" datetime, foreign key("user_id") references "users"("id") on delete cascade);
CREATE TABLE IF NOT EXISTS "withdrawals" ("id" integer primary key autoincrement not null, "user_id" integer not null, "amount" numeric not null, "method" varchar not null, "status" varchar not null default 'pending', "details" text, "rejection_reason" text, "created_at" datetime, "updated_at" datetime, foreign key("user_id") references "users"("id") on delete cascade);
CREATE TABLE IF NOT EXISTS "admin_password_resets" ("id" integer primary key autoincrement not null, "email" varchar not null, "token" varchar not null, "expires_at" datetime not null, "created_at" datetime, "updated_at" datetime);
CREATE TABLE IF NOT EXISTS "partnerships" ("id" integer primary key autoincrement not null, "name" varchar not null, "description" text, "amount" numeric not null, "benefits" text, "is_active" tinyint(1) not null default '1', "created_at" datetime, "updated_at" datetime);
CREATE TABLE IF NOT EXISTS "investments" ("id" integer primary key autoincrement not null, "user_id" integer not null, "investment_plan_id" integer not null, "amount" numeric not null, "profit" numeric not null default ('0'), "start_date" datetime not null, "end_date" datetime, "last_profit_at" datetime, "status" varchar not null default ('active'), "created_at" datetime, "updated_at" datetime, "investment_group_id" integer, foreign key("investment_plan_id") references investment_plans("id") on delete cascade on update no action, foreign key("user_id") references users("id") on delete cascade on update no action, foreign key("investment_group_id") references "investment_groups"("id") on delete set null);
CREATE TABLE IF NOT EXISTS "investment_groups" ("id" integer primary key autoincrement not null, "name" varchar not null, "total_profit" numeric not null default ('0'), "status" varchar not null default ('open'), "maturity_date" datetime, "created_at" datetime, "updated_at" datetime, "investment_plan_id" integer, foreign key("investment_plan_id") references "investment_plans"("id") on delete cascade);
CREATE INDEX "sessions_user_id_index" on "sessions" ("user_id");
CREATE INDEX "sessions_last_activity_index" on "sessions" ("last_activity");
CREATE INDEX "cache_expiration_index" on "cache" ("expiration");
CREATE INDEX "cache_locks_expiration_index" on "cache_locks" ("expiration");
CREATE INDEX "jobs_queue_index" on "jobs" ("queue");
CREATE UNIQUE INDEX "failed_jobs_uuid_unique" on "failed_jobs" ("uuid");
CREATE INDEX "personal_access_tokens_tokenable_type_tokenable_id_index" on "personal_access_tokens" ("tokenable_type", "tokenable_id");
CREATE UNIQUE INDEX "personal_access_tokens_token_unique" on "personal_access_tokens" ("token");
CREATE INDEX "personal_access_tokens_expires_at_index" on "personal_access_tokens" ("expires_at");
CREATE UNIQUE INDEX "users_email_unique" on "users" ("email");
CREATE UNIQUE INDEX "users_google_id_unique" on "users" ("google_id");
CREATE UNIQUE INDEX "users_apple_id_unique" on "users" ("apple_id");
CREATE UNIQUE INDEX "transactions_reference_unique" on "transactions" ("reference");
CREATE INDEX "admin_password_resets_email_index" on "admin_password_resets" ("email");
CREATE UNIQUE INDEX "users_lxp_id_unique" on "users" ("lxp_id");
COMMIT;
